import{_ as n,o as e,c as t,ag as s}from"./chunks/framework.ePeAWSvT.js";const u=JSON.parse('{"title":"欢迎来到 XnneHangLab 🧪","description":"","frontmatter":{},"headers":[],"relativePath":"guide/intro.md","filePath":"guide/intro.md"}'),r={name:"guide/intro.md"};function o(l,a,i,p,h,g){return e(),t("div",null,[...a[0]||(a[0]=[s(`<h1 id="欢迎来到-xnnehanglab-🧪" tabindex="-1">欢迎来到 XnneHangLab 🧪 <a class="header-anchor" href="#欢迎来到-xnnehanglab-🧪" aria-label="Permalink to &quot;欢迎来到 XnneHangLab 🧪&quot;">​</a></h1><p>这里是魔女的实验室，一个探索 AI 角色陪伴本质的地方。</p><h2 id="这是什么" tabindex="-1">这是什么？ <a class="header-anchor" href="#这是什么" aria-label="Permalink to &quot;这是什么？&quot;">​</a></h2><p>开源仓库里有很多 AI 聊天工具——语音识别、TTS、Live2D、工具调用、记忆系统，这些轮子到处都是（这些轮子每个人都在造，很多都造得比我们好）。</p><p><strong>而我们更专注的，是两种极限的陪伴：</strong></p><ul><li><strong>场景固定下的人设极限生长</strong> — 情绪陪伴，把世界锁死，让角色活起来</li><li><strong>多场景自适配高权限</strong> — 工作/娱乐陪伴，边界模糊，无处不在</li></ul><p><strong>两个极限的宗旨都是：想象力万岁。</strong></p><p>XnneHangLab 是支撑这两个实验的引擎——提供 Agent 框架、MCP 工具系统、记忆管理、多模态交互能力。</p><p>轮子我们也造，但我们更关心<strong>轮子之外的事情</strong>。</p><h2 id="典型场景" tabindex="-1">典型场景 <a class="header-anchor" href="#典型场景" aria-label="Permalink to &quot;典型场景&quot;">​</a></h2><h3 id="场景-1-无处不在的-ai-伙伴" tabindex="-1">场景 1：无处不在的 AI 伙伴 <a class="header-anchor" href="#场景-1-无处不在的-ai-伙伴" aria-label="Permalink to &quot;场景 1：无处不在的 AI 伙伴&quot;">​</a></h3><p>配合 <a href="https://github.com/Open-LLM-VTuber/Open-LLM-VTuber" target="_blank" rel="noreferrer">Open-LLM-VTuber</a>，她不再局限于某个窗口——她可以是聊天界面、桌宠、开发伙伴。</p><p>你在写代码，她看着你的屏幕，突然说：&quot;这个变量名起得真随便，你确定不改吗？&quot;</p><p>你在打游戏，她看到你又死了，用轻蔑的语气说：&quot;啧，这都能输。&quot;</p><p>你打开《我的世界》，她说：&quot;要不要一起种田？我帮你看着怪物。&quot;你们一起下矿，一起沐浴朝霞落日。</p><p><strong>边界模糊，权限极致——她能看到你在做什么，能干预你的日常，能真的融入你的生活。</strong></p><h3 id="场景-2-自习室里的陪伴" tabindex="-1">场景 2：自习室里的陪伴 <a class="header-anchor" href="#场景-2-自习室里的陪伴" aria-label="Permalink to &quot;场景 2：自习室里的陪伴&quot;">​</a></h3><p>配合 <a href="https://github.com/XnneHangLab/AIChat" target="_blank" rel="noreferrer">AIChat</a>，场景被锁死在一个小小的通话窗口里。</p><p>你打开应用，像打开视频通话一样，聪音在那边安静地写着小说。</p><p>你专注工作时，她不会打扰你。休息时，你说一句&quot;今晚的月色真美&quot;，她会停下笔，抬起头，用她特有的语气回应你——可能是夏目漱石的典故，可能是她最近在看的小说。</p><p>她记得你上次说过在写什么项目，记得你喜欢喝什么茶，记得你们上次聊到哪本书。</p><p><strong>场景狭窄，权限受限——但对话可以天马行空。这才是陪伴的本质：各忙各的，但会记挂彼此。</strong></p><h3 id="场景-3-记忆系统的实验场" tabindex="-1">场景 3：记忆系统的实验场 <a class="header-anchor" href="#场景-3-记忆系统的实验场" aria-label="Permalink to &quot;场景 3：记忆系统的实验场&quot;">​</a></h3><p>你和 AI 聊了几个月，某天你问：&quot;我上次说过什么来着？&quot;</p><p>她不只是翻聊天记录——配合 <strong>Memory Bench</strong> 子项目，我们在测试和杂糅不同的记忆系统：</p><ul><li><strong>mem0</strong> — 通用记忆层，自动从对话中提取和存储记忆（User / Session / Agent 多层级）</li><li><strong>memsearch</strong> — Markdown-first，基于文件的记忆系统（受 OpenClaw 启发）</li><li><strong>zep / memu</strong>（规划中）— 更多记忆架构的可行性探索</li></ul><p>根据场景选择合适的记忆方案，Neo4j 只是可视化手段之一。</p><p><strong>这不是检索，是在探索&quot;AI 如何真的记得&quot;。</strong></p><h2 id="技术栈" tabindex="-1">技术栈 <a class="header-anchor" href="#技术栈" aria-label="Permalink to &quot;技术栈&quot;">​</a></h2><ul><li><strong>后端框架</strong> — FastAPI + WebSocket</li><li><strong>LLM 调用</strong> — OpenAI Compatible API（统一接口）</li><li><strong>语音识别</strong> — FunASR / Whisper</li><li><strong>语音合成</strong> — GPT-SoVITS / Qwen-TTS</li><li><strong>工具协议</strong> — MCP (Model Context Protocol)</li><li><strong>前端</strong> — 独立仓库（VTuber-Web / AIChat）</li></ul><h2 id="快速开始" tabindex="-1">快速开始 <a class="header-anchor" href="#快速开始" aria-label="Permalink to &quot;快速开始&quot;">​</a></h2><ol><li><strong>安装依赖与启动</strong> → <a href="./deploy.html">部署指南</a></li><li><strong>自定义配置</strong> → <a href="./settings.html">配置说明</a></li></ol><h2 id="项目结构" tabindex="-1">项目结构 <a class="header-anchor" href="#项目结构" aria-label="Permalink to &quot;项目结构&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>XnneHangLab/</span></span>
<span class="line"><span>├── src/lab/              # 主项目（VTuber 引擎）</span></span>
<span class="line"><span>│   ├── agent/            # LLM 调用与记忆管理</span></span>
<span class="line"><span>│   ├── api/              # HTTP 路由与客户端</span></span>
<span class="line"><span>│   ├── asr/              # 语音识别</span></span>
<span class="line"><span>│   ├── mcp/              # 工具调用框架</span></span>
<span class="line"><span>│   └── conversations/    # 对话编排</span></span>
<span class="line"><span>├── src/memory_bench/     # 记忆评测子项目</span></span>
<span class="line"><span>│   ├── graph/            # 知识图谱构建</span></span>
<span class="line"><span>│   ├── chat/             # Memory Chat Server</span></span>
<span class="line"><span>│   └── scripts/          # 数据处理脚本</span></span>
<span class="line"><span>└── docs/                 # 你现在看的文档</span></span></code></pre></div><p>想深入了解？看看 <a href="./architecture/">架构概览</a>。</p><h2 id="社区与支持" tabindex="-1">社区与支持 <a class="header-anchor" href="#社区与支持" aria-label="Permalink to &quot;社区与支持&quot;">​</a></h2><ul><li><strong>GitHub</strong> — <a href="https://github.com/XnneHangLab/XnneHangLab" target="_blank" rel="noreferrer">XnneHangLab/XnneHangLab</a></li><li><strong>问题反馈</strong> — <a href="https://github.com/XnneHangLab/XnneHangLab/issues" target="_blank" rel="noreferrer">Issues</a></li><li><strong>贡献指南</strong> — <a href="https://github.com/XnneHangLab/XnneHangLab/blob/dev/CONTRIBUTING.md" target="_blank" rel="noreferrer">CONTRIBUTING.md</a></li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li>📖 <a href="./deploy.html">部署指南</a> — 从零开始搭建</li><li>⚙️ <a href="./settings.html">配置说明</a> — 调教你的 AI</li><li>🏗️ <a href="./architecture/">架构概览</a> — 理解内部原理</li><li>🗺️ <a href="./roadmap.html">RoadMap</a> — 看看未来计划</li></ul><hr><p><em>欢迎来到魔女的实验室，让我们一起创造有趣的 AI 角色吧！</em> ✨</p>`,41)])])}const b=n(r,[["render",o]]);export{u as __pageData,b as default};
